### Method 1: Using `fs.watch`

1. **Create a new file** (e.g., `fileWatcher.js`).
2. **Add the following code**:

```javascript
const fs = require('fs');
const path = require('path');

// Specify the directory to watch
const directoryToWatch = './watched_directory'; // Change this to your directory

// Ensure the directory exists
if (!fs.existsSync(directoryToWatch)) {
    fs.mkdirSync(directoryToWatch);
}

// Watch the directory for changes
fs.watch(directoryToWatch, (eventType, filename) => {
    if (eventType === 'rename' && filename.endsWith('.csv')) {
        const filePath = path.join(directoryToWatch, filename);
        // Check if the file exists to confirm it was added
        fs.access(filePath, fs.constants.F_OK, (err) => {
            if (!err) {
                console.log(`New CSV file detected: ${filename}`);
            }
        });
    }
});

console.log(`Watching for new .csv files in ${directoryToWatch}...`);
```

### Method 2: Using `chokidar`

